import React from 'react';

function TestDishSearch() {
  return (
    <div>
      <h1>🎉 SEARCH PAGE IS WORKING!</h1>
      <p>This is the dish search page. It's working now!</p>

      <div style={{padding: '20px', backgroundColor: '#f0f0f0', margin: '20px 0'}}>
        <h2>Test Dishes:</h2>
        <ul>
          <li>Masala Dosa - ₹120</li>
          <li>Chicken Biryani - ₹280</li>
          <li>Idli Sambar - ₹80</li>
        </ul>
      </div>

      <p>If you can see this, the search page is working!</p>
    </div>
  );
}

export default TestDishSearch;
